INSERT INTO "public"."faq" ("id", "created_at", "updated_at", "question", "answer", "is_open", "display_order", "is_active", "category", "is_highlight") VALUES ('2', '2025-09-16 10:44:18.495437+00', '2025-09-26 12:31:42.468+00', 'What is CESAFI?', 'Established in 2001, succeeding the Cebu Amateur Athletic Association (CAAA), CESAFI is the biggest sports and academic association in the Visayas and Mindanao, currently consisting of 17 member schools.

CESAFI''s events include basketball, volleyball, football, esports, swimming, badminton, scrabble, dancesports, and many more.
', 'true', '1', 'true', 'General', 'true'), ('3', '2025-09-16 10:44:18.495437+00', '2025-09-26 12:38:05.632+00', 'How can I watch CESAFI games?', 'You can watch the CESAFI basketball matches at the Cebu Coliseum. Meanwhile, the volleyball matches are played at the University of Southern Philippines Foundation (USPF) gymnasium and at the University of San Carlos (USC) Downtown campus gymnasium. 

You can also watch the CESAFI basketball macthes in the CESAFI  Facebook page, Puso Pilipinas, and Smart Live Stream app. Some of the volleyball matches will also be broadcast live. Meanwhile, you can watch the CESAFI Esports Legue (CEL) in the CEL Facebook page, and Smart Live Stream app. 

The venues for other sporting events are held at different campuses of CESAFI-member schools.', 'true', '2', 'true', 'Sports', 'true'), ('4', '2025-09-16 10:44:18.495437+00', '2025-09-26 12:39:07.466+00', 'What schools are affiliated with CESAFI ? ', 'CESAFI includes prestigious educational institutions across Cebu. Visit our Schools page to see all member schools, their teams, and athletic programs.', 'false', '3', 'true', 'Schools', 'true'), ('5', '2025-09-16 10:44:18.495437+00', '2025-09-26 12:46:41.008+00', 'How do I become a CESAFI volunteer?', 'Bona fide students from CESAFI-member schools are welcome to join the league during the application phase, which will take place before the season starts.', 'false', '4', 'true', 'Volunteers', 'true'), ('6', '2025-09-16 10:44:18.495437+00', '2025-09-26 12:21:35.765+00', 'When was CESAFI founded?', 'Cebu Schools Athletic Foundation, Inc. (CESAFI) was founded in 2001, by sir Felix "Boy" Tiukinhoy Jr., the league''s current commissioner. Before the creation of the CESAFI, there was already a collegiate league in Cebu, named the Cebu Amateur Athletic Association (CAAA), also formerly known as Cebu Collegiate Athletic Association (CCAA).', 'false', '5', 'true', 'General', 'false'), ('7', '2025-09-16 10:44:18.495437+00', '2025-09-26 12:47:13.509+00', 'What sports does CESAFI organize?', 'CESAFI organizes various sports including basketball, volleyball, football, track and field, swimming, badminton, table tennis, and many other athletic competitions throughout the academic year.', 'false', '6', 'true', 'Sports', 'false'), ('10', '2025-09-16 10:44:18.495437+00', '2025-09-26 12:44:31.194+00', 'What are the different divisions in CESAFI?', 'CESAFI organizes competitions in various divisions including high school and college levels, with separate categories for men and women in most sports.', 'false', '7', 'true', 'Schools', 'false'), ('13', '2025-09-16 10:44:18.495437+00', '2025-09-26 12:44:36.047+00', 'When do CESAFI seasons typically run?', 'CESAFI season typically begins on September, and generally align with the academic calendar, with different sports having their seasons throughout the school year.', 'false', '8', 'true', 'Events', 'false');